import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [recognizedText, setRecognizedText] = useState("");

  // 사진 촬영 함수
  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 100,
        allowEditing: true, // 글자 부위만 자르면 정확도가 더 올라갑니다!
        resultType: CameraResultType.Base64,
        source: CameraSource.Camera,
      });
      setPhoto(image.base64String);
      setRecognizedText("");
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  // 백엔드 서버로 전송하여 OCR 수행
  const startOCR = async () => {
    if (!photo) return;
    setUploading(true);

    try {
      const response = await fetch("http://localhost:3001/ocr", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ image: photo }),
      });

      if (!response.ok) throw new Error("서버 응답 에러");

      const data = await response.json();
      setRecognizedText(data.text);
    } catch (err) {
      console.error("통신 오류:", err);
      alert("백엔드 서버(3001)가 켜져 있는지 확인하세요!");
    } finally {
      setUploading(false);
    }
  };

  const deletePhoto = () => {
    setPhoto(null);
    setRecognizedText("");
  };

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <h1 style={headerTitleStyle}>🔍 AI 글자 인식 스캐너</h1>
      </header>

      <main style={mainStyle}>
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img
                src={`data:image/jpeg;base64,${photo}`}
                alt="Preview"
                style={imageStyle}
              />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle}>
              <div style={placeholderIconStyle}>📷</div>
              <p style={placeholderTextStyle}>분석할 대상을 촬영해 주세요</p>
            </div>
          )}
        </div>

        <div style={infoSectionStyle}>
          {uploading ? (
            <div style={loadingAreaStyle}>
              <div style={spinnerStyle}></div>
              <p style={statusStyle}>AI가 글자를 분석하고 있습니다...</p>
            </div>
          ) : recognizedText ? (
            <div style={resultContainerStyle}>
              <label style={labelStyle}>인식 결과</label>
              <textarea
                style={textareaStyle}
                value={recognizedText}
                onChange={(e) => setRecognizedText(e.target.value)}
              />
            </div>
          ) : photo ? (
            <p style={statusStyle}>준비 완료! 서버로 보내서 분석할까요?</p>
          ) : null}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button onClick={takePhoto} style={mainButtonStyle}>
            사진 촬영하기
          </button>
        ) : (
          <button
            onClick={startOCR}
            style={{ ...mainButtonStyle, backgroundColor: "#28a745" }}
            disabled={uploading}
          >
            {uploading ? "분석 중..." : "글자 인식 시작"}
          </button>
        )}
      </footer>
    </div>
  );
}

// 스타일 가이드 (가독성을 위해 핵심만 유지)
const wrapperStyle = {
  backgroundColor: "#f4f7f6",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
};
const headerStyle = {
  paddingTop: "50px",
  paddingBottom: "15px",
  backgroundColor: "#fff",
  textAlign: "center",
  borderBottom: "1px solid #ddd",
};
const headerTitleStyle = { fontSize: "20px", margin: 0, fontWeight: "800" };
const mainStyle = {
  flex: 1,
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const photoCardStyle = {
  width: "100%",
  maxWidth: "360px",
  aspectRatio: "1/1",
  backgroundColor: "#fff",
  borderRadius: "24px",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  border: "2px dashed #ccc",
  boxShadow: "0 8px 20px rgba(0,0,0,0.05)",
};
const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };
const placeholderStyle = { textAlign: "center", color: "#aaa" };
const placeholderIconStyle = { fontSize: "50px" };
const placeholderTextStyle = { fontSize: "15px", marginTop: "10px" };
const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "30px",
  height: "30px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.5)",
  color: "#fff",
  border: "none",
};
const infoSectionStyle = {
  width: "100%",
  maxWidth: "360px",
  marginTop: "20px",
};
const statusStyle = { fontSize: "14px", color: "#666", textAlign: "center" };
const resultContainerStyle = { textAlign: "left" };
const labelStyle = { fontSize: "12px", color: "#28a745", fontWeight: "bold" };
const textareaStyle = {
  width: "100%",
  padding: "15px",
  marginTop: "8px",
  borderRadius: "12px",
  border: "2px solid #28a745",
  fontSize: "14px",
  minHeight: "120px",
  boxSizing: "border-box",
};
const loadingAreaStyle = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const spinnerStyle = {
  width: "30px",
  height: "30px",
  border: "4px solid #f3f3f3",
  borderTop: "4px solid #007bff",
  borderRadius: "50%",
  animation: "spin 1s linear infinite",
};
const footerStyle = { padding: "20px", backgroundColor: "#fff" };
const mainButtonStyle = {
  width: "100%",
  padding: "16px",
  borderRadius: "14px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "16px",
  fontWeight: "bold",
};

export default App;
